function registrationDefault(emirate) {
  return emirate === "Dubai" ? 580 : 1100;
}

// Banks in this market typically finance up to 80% of the car's declared/evaluated
// value. To secure 100% financing of the actual price, the value quoted to the
// bank is grossed up so that 80% of it equals the amount to be financed; the
// remaining 20% is paid by the customer as down payment (to the bank or seller).
const BANK_LOAN_LTV = 0.8;
const CAR_STATUSES = ["Available", "Upcoming", "Reserved", "Sold", "In Service"];
