const uid = () => Math.random().toString(36).slice(2, 10);
const parseNum = (val) => {
  if (val === null || val === undefined || val === "") return 0;
  const parsed = Number(String(val).replace(/,/g, ""));
  return isNaN(parsed) ? 0 : parsed;
};
const money = (n) => {
  const num = parseNum(n);
  return num === 0 ? "0" : num.toLocaleString("en-AE", { maximumFractionDigits: 0 });
};
const todayISO = () => new Date().toISOString().slice(0, 10);
const daysSince = (iso) => {
  if (!iso) return null;
  const cleanIso = String(iso).split(/[ T]/)[0];
  const parts = cleanIso.split(/[-/]/);
  if (parts.length < 3) return null;
  // Support YYYY-MM-DD and DD/MM/YYYY: if parts[2] is 4 digits it's the year
  let year, month, day;
  if (String(parts[2]).length === 4) {
    year = parseInt(parts[2], 10);
    month = parseInt(parts[1], 10) - 1;
    day = parseInt(parts[0], 10);
  } else {
    year = parseInt(parts[0], 10);
    month = parseInt(parts[1], 10) - 1;
    day = parseInt(parts[2], 10);
  }
  const then = new Date(year, month, day);
  if (isNaN(then.getTime())) return null;
  const now = new Date();
  const nowMidnight = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  const thenMidnight = new Date(then.getFullYear(), then.getMonth(), then.getDate());
  return Math.round((nowMidnight - thenMidnight) / 86400000);
};
const AGING_THRESHOLD_DAYS = 90;
const fmtDate = (iso) => {
  if (!iso) return "";
  const d = new Date(iso + "T00:00:00");
  return d.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" });
};

/* ---------- amount in words (AED) ---------- */
function numberToWords(numIn) {
  const num = Math.round(Number(numIn) || 0);
  if (num === 0) return "Zero";
  const ones = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten",
    "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"];
  const tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"];
  const chunk = (n) => {
    let s = "";
    if (n >= 100) { s += ones[Math.floor(n / 100)] + " Hundred "; n %= 100; }
    if (n >= 20) { s += tens[Math.floor(n / 10)] + " "; n %= 10; }
    if (n > 0) s += ones[n] + " ";
    return s.trim();
  };
  const parts = [];
  let n = num;
  const scales = [[1e9, "Billion"], [1e6, "Million"], [1e3, "Thousand"]];
  for (const [div, label] of scales) {
    if (n >= div) {
      parts.push(chunk(Math.floor(n / div)) + " " + label);
      n %= div;
    }
  }
  if (n > 0) parts.push(chunk(n));
  return parts.join(" ").replace(/\s+/g, " ").trim();
}
const amountInWords = (n) => `${numberToWords(n)} Dirhams Only`;

