function Pill({ children, tone = "muted" }) {
  const map = {
    success: { bg: C.successBg, fg: C.success },
    warn: { bg: C.warnBg, fg: C.warn },
    danger: { bg: C.dangerBg, fg: C.danger },
    muted: { bg: C.mutedBg, fg: C.muted },
    gold: { bg: "#F4E9D2", fg: C.goldDeep },
  }[tone];
  return (
    <span
      className="text-[11px] font-semibold uppercase tracking-wide px-2 py-1 rounded-full inline-block"
      style={{ background: map.bg, color: map.fg }}
    >
      {children}
    </span>
  );
}

function Stamp({ text, tone = "muted" }) {
  const fg = { success: C.success, warn: C.warn, danger: C.danger, muted: C.muted, gold: C.goldDeep }[tone];
  return (
    <div
      className="inline-block px-3 py-1 text-[11px] font-bold uppercase tracking-widest rounded-sm"
      style={{
        border: `2px solid ${fg}`,
        color: fg,
        transform: "rotate(-4deg)",
        fontFamily: "'IBM Plex Mono', monospace",
        letterSpacing: "0.12em",
      }}
    >
      {text}
    </div>
  );
}

function Field({ label, children }) {
  return (
    <label className="block mb-3">
      <span className="block text-xs font-semibold mb-1" style={{ color: C.muted }}>{label}</span>
      {children}
    </label>
  );
}

const inputCls = "w-full px-3 py-2 rounded-lg text-sm outline-none";
const inputStyle = { border: `1px solid ${C.line}`, background: C.card, color: C.ink };

function TextInput(props) {
  return <input {...props} className={inputCls + " " + (props.className || "")} style={{ ...inputStyle, ...(props.style || {}) }} />;
}
function Select(props) {
  return <select {...props} className={inputCls + " " + (props.className || "")} style={{ ...inputStyle, ...(props.style || {}) }} />;
}

function Btn({ children, onClick, tone = "ink", full, type = "button", size = "md", disabled = false }) {
  const bg = { ink: C.ink, gold: C.gold, danger: C.danger, ghost: "transparent" }[tone];
  const fg = tone === "ghost" ? C.ink : tone === "gold" ? C.ink : "#fff";
  const pad = size === "sm" ? "px-3 py-1.5 text-xs" : "px-4 py-2.5 text-sm";
  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled}
      className={`${pad} rounded-lg font-semibold flex items-center justify-center gap-1.5 active:scale-[0.98] transition ${full ? "w-full" : ""}`}
      style={{ background: bg, color: fg, border: tone === "ghost" ? `1px solid ${C.line}` : "none", opacity: disabled ? 0.5 : 1 }}
    >
      {children}
    </button>
  );
}

